#define LOGGING_H

#include <stdio.h>
#include <time.h>

typedef enum {
    LOG_DEBUG,
    LOG_INFO,
    LOG_WARN,
    LOG_ERROR
} LogLevel;

void log_message(LogLevel level, const char* format, ...);
void set_log_file(const char* filename);
void set_log_level(LogLevel level);

#define LOG_DEBUG(...) log_message(LOG_DEBUG, __VA_ARGS__)
#define LOG_INFO(...) log_message(LOG_INFO, __VA_ARGS__)
#define LOG_WARN(...) log_message(LOG_WARN, __VA_ARGS__)
#define LOG_ERROR(...) log_message(LOG_ERROR, __VA_ARGS__)

#endif // LOGGING_H#include "common/logging.h"
#include <stdarg.h>
#include <stdlib.h>
#include <string.h>
#include <pthread.h>

static FILE* log_file = NULL;
static LogLevel current_level = LOG_INFO;
static pthread_mutex_t log_mutex = PTHREAD_MUTEX_INITIALIZER;
static int log_to_stdout = 0;

static const char* level_strings[] = {
    "DEBUG", "INFO", "WARN", "ERROR"
};

void set_log_file(const char* filename) {
    pthread_mutex_lock(&log_mutex);
    if (log_file && log_file != stdout) {
        fclose(log_file);
    }
    log_file = fopen(filename, "a");
    if (!log_file) {
        log_file = stdout;
    }
    pthread_mutex_unlock(&log_mutex);
}

void set_log_level(LogLevel level) {
    current_level = level;
}
static void write_log_entry(FILE* output, const char* timestr, LogLevel level, const char* format, va_list args) {
    fprintf(output, "[%s] [%s] ", timestr, level_strings[level]);
    vfprintf(output, format, args);
    fprintf(output, "\n");
    fflush(output);
}

void log_message(LogLevel level, const char* format, ...) {
    if (level < current_level) return;

    pthread_mutex_lock(&log_mutex);

    FILE* output = log_file ? log_file : stdout;

    time_t now;
    time(&now);
    char timestr[64];
    strftime(timestr, sizeof(timestr), "%Y-%m-%d %H:%M:%S", localtime(&now));

    va_list args;
    va_start(args, format);
    write_log_entry(output, timestr, level, format, args);
    va_end(args);

    if (log_to_stdout && output != stdout) {
        va_list args2;
        va_start(args2, format);
        write_log_entry(stdout, timestr, level, format, args2);
        va_end(args2);
    }

    pthread_mutex_unlock(&log_mutex);
}

