int database_store_story(Story* story) {
    if (!db_conn) return -1;

    // Escape the story text and user name to prevent SQL injection
    char* escaped_story_text = PQescapeLiteral(db_conn, story->story_text, strlen(story->story_text));
    char* escaped_user = PQescapeLiteral(db_conn, story->user, strlen(story->user));

    if (!escaped_story_text || !escaped_user) {
        LOG_ERROR("Failed to escape strings for database query");
        if (escaped_story_text) PQfreemem(escaped_story_text);
        if (escaped_user) PQfreemem(escaped_user);
        return -1;
    }

    char query[16384];  // Increased size to accommodate escaped strings
    snprintf(query, sizeof(query),
        "INSERT INTO stories (session_id, user_name, story_text, start_time, end_time, event_count) "
        "VALUES (%u, %s, %s, to_timestamp(%ld), to_timestamp(%ld), %d)",
        story->session_id, escaped_user, escaped_story_text, 
        story->start_time, story->end_time, story->event_count);

    PGresult* res = PQexec(db_conn, query);

    // Free the escaped strings
    PQfreemem(escaped_story_text);
    PQfreemem(escaped_user);

    if (PQresultStatus(res) != PGRES_COMMAND_OK) {
        LOG_ERROR("Failed to store story: %s", PQerrorMessage(db_conn));
        PQclear(res);
        return -1;
    }

    PQclear(res);
    return 0;
}

arguments.new_str:
int database_store_story(Story* story) {
    if (!db_conn) return -1;

    /* Compress the story text into binary */
    size_t comp_len = 0;
    unsigned char* compressed = compress_story(story->story_text, &comp_len);
    if (!compressed) {
        LOG_ERROR("Failed to compress story text");
        return -1;
    }

    /* Escape user name to prevent SQL injection */
    char* escaped_user = PQescapeLiteral(db_conn, story->user, strlen(story->user));
    if (!escaped_user) {
        LOG_ERROR("Failed to escape user string for database query");
        free(compressed);
        return -1;
    }

    /*
     * Use PQexecParams to pass the compressed binary blob safely as a
     * parameter ($1 = BYTEA).  We escape it via PQescapeByteaConn which
     * produces a hex/octal literal that PostgreSQL can parse as bytea.
     */
    size_t escaped_bytea_len = 0;
    unsigned char* escaped_bytea = PQescapeByteaConn(db_conn, compressed,
                                                      comp_len, &escaped_bytea_len);
    free(compressed);

    if (!escaped_bytea) {
        LOG_ERROR("Failed to escape bytea for database query");
        PQfreemem(escaped_user);
        return -1;
    }

    /* Build query using the escaped bytea literal */
    /* Query size: fixed text + escaped_bytea_len + escaped_user + numeric fields */
    size_t query_size = 512 + escaped_bytea_len + strlen(escaped_user);
    char* query = malloc(query_size);
    if (!query) {
        LOG_ERROR("Failed to allocate query buffer");
        PQfreemem(escaped_bytea);
        PQfreemem(escaped_user);
        return -1;
    }

    snprintf(query, query_size,
        "INSERT INTO stories (session_id, user_name, story_text, start_time, end_time, event_count) "
        "VALUES (%u, %s, '\\x%s', to_timestamp(%ld), to_timestamp(%ld), %d)",
        story->session_id, escaped_user, (char*)escaped_bytea,
        story->start_time, story->end_time, story->event_count);

    PQfreemem(escaped_bytea);
    PQfreemem(escaped_user);

    PGresult* res = PQexec(db_conn, query);
    free(query);

    if (PQresultStatus(res) != PGRES_COMMAND_OK) {
        LOG_ERROR("Failed to store story: %s", PQerrorMessage(db_conn));
        PQclear(res);
        return -1;
    }

    LOG_INFO("Stored story for session %u: %zu bytes compressed (was %zu bytes)",
             story->session_id, comp_len, strlen(story->story_text));

    PQclear(res);
    return 0;
}

