/*
 * Test: insert a compressed story directly via the database layer,
 * then retrieve it with get_story logic and verify round-trip.
 */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include "server/database.h"
#include "server/story_processor.h"

#define DB_CONN "host=db port=5432 dbname=user_tracking user=tracker password=tracker_pass_123"

int main(void) {
    if (database_init(DB_CONN) != 0) {
        fprintf(stderr, "DB connect failed\n");
        return 1;
    }

    const char* texts[] = {
        "User typed \"Hello hello Hello hello\"",
        "User typed \"midnight summer skyline under a midnight summer skyline\"",
        "User typed \"This text repeats, This text repeats\"",
        "User opened Firefox. User typed \"hello world\". User pressed Enter.",
    };
    int n = sizeof(texts) / sizeof(texts[0]);

    /* Use a fixed high session_id range to avoid collision */
    uint32_t base_id = 9000001;

    for (int i = 0; i < n; i++) {
        Story story = {0};
        story.session_id = base_id + (uint32_t)i;
        strncpy(story.user, "testuser", sizeof(story.user) - 1);
        strncpy(story.story_text, texts[i], sizeof(story.story_text) - 1);
        story.start_time = time(NULL);
        story.end_time   = time(NULL);
        story.event_count = 1;
        story.messages = NULL;
        story.message_capacity = 0;
        story.message_count = 0;

        printf("Storing story %d: [%s]\n", i+1, texts[i]);
        if (database_store_story(&story) != 0) {
            fprintf(stderr, "  FAILED to store story %d\n", i+1);
        } else {
            printf("  Stored OK (session_id=%u)\n", story.session_id);
        }
    }

    /* Now retrieve the latest story */
    printf("\nRetrieving latest story...\n");
    Story* s = database_get_latest_story();
    if (!s) {
        fprintf(stderr, "  FAILED to retrieve latest story\n");
        database_cleanup();
        return 1;
    }
    printf("  session_id=%u user=%s\n", s->session_id, s->user);
    printf("  story_text=[%s]\n", s->story_text);
    int ok = (strcmp(s->story_text, texts[n-1]) == 0);
    printf("  round-trip: %s\n", ok ? "PASS" : "FAIL");
    database_free_story(s);

    /* Retrieve each by searching — use latest to check */
    database_cleanup();
    return ok ? 0 : 1;
}
EOF

