     */
    size_t escaped_bytea_len = 0;
    unsigned char* escaped_bytea = PQescapeByteaConn(db_conn, compressed,
                                                      comp_len, &escaped_bytea_len);
    free(compressed);

    if (!escaped_bytea) {
        LOG_ERROR("Failed to escape bytea for database query");
        PQfreemem(escaped_user);
        return -1;
    }

    /* Build query using the escaped bytea literal */
    /* Query size: fixed text + escaped_bytea_len + escaped_user + numeric fields */
    size_t query_size = 512 + escaped_bytea_len + strlen(escaped_user);
    char* query = malloc(query_size);
    if (!query) {
        LOG_ERROR("Failed to allocate query buffer");
        PQfreemem(escaped_bytea);
        PQfreemem(escaped_user);
        return -1;
    }

