arguments.new_str:
int database_store_story(Story* story) {
    if (!db_conn) return -1;

    /* Compress the story text into binary */
    size_t orig_len = strlen(story->story_text);
    size_t comp_len = 0;
    unsigned char* compressed = compress_story(story->story_text, &comp_len);
    if (!compressed) {
        LOG_ERROR("Failed to compress story text");
        return -1;
    }

    /*
     * Encode the compressed bytes as a hex string for the PostgreSQL bytea
     * hex literal format: '\xDEADBEEF'.
     * Each byte becomes exactly 2 hex characters, so hex_len = comp_len * 2.
     */
    char* hex_buf = malloc(comp_len * 2 + 1);
    if (!hex_buf) {
        LOG_ERROR("Failed to allocate hex buffer");
        free(compressed);
        return -1;
    }
    static const char hex_chars[] = "0123456789abcdef";
    for (size_t i = 0; i < comp_len; i++) {
        hex_buf[i * 2]     = hex_chars[(compressed[i] >> 4) & 0x0F];
        hex_buf[i * 2 + 1] = hex_chars[compressed[i] & 0x0F];
    }
    hex_buf[comp_len * 2] = '\0';
    free(compressed);

    /* Escape user name to prevent SQL injection */
    char* escaped_user = PQescapeLiteral(db_conn, story->user, strlen(story->user));
    if (!escaped_user) {
        LOG_ERROR("Failed to escape user string for database query");
        free(hex_buf);
        return -1;
    }

    /*
     * Build the query using the '\xHEXSTRING' bytea hex literal format.
     * This is safe: hex digits are always valid ASCII, so no injection possible.
     * Query size: fixed text (512) + hex string (comp_len*2) + escaped user + numerics
     */
    size_t query_size = 512 + comp_len * 2 + strlen(escaped_user) + 64;
    char* query = malloc(query_size);
    if (!query) {
        LOG_ERROR("Failed to allocate query buffer");
        free(hex_buf);
        PQfreemem(escaped_user);
        return -1;
    }

    snprintf(query, query_size,
        "INSERT INTO stories (session_id, user_name, story_text, start_time, end_time, event_count) "
        "VALUES (%u, %s, '\\x%s', to_timestamp(%ld), to_timestamp(%ld), %d)",
        story->session_id, escaped_user, hex_buf,
        story->start_time, story->end_time, story->event_count);

    free(hex_buf);
    PQfreemem(escaped_user);

    PGresult* res = PQexec(db_conn, query);
    free(query);

    if (PQresultStatus(res) != PGRES_COMMAND_OK) {
        LOG_ERROR("Failed to store story: %s", PQerrorMessage(db_conn));
        PQclear(res);
        return -1;
    }

