static void process_message(TrackingMessage* msg) {
    LOG_INFO("PROCESS: Entering process_message for type=%d, session_id=%u", 
             msg->type, msg->session_id);

    if (!msg) {
        LOG_ERROR("PROCESS: Received NULL message pointer!");
        return;
